  if (clean.endsWith(fence)) clean = clean.slice(0, -3).trim();
  return clean;
}

function parseAi(raw) {
  const fallback = {
    decision: 'IGNORE',
    category: 'IGNORE',
    subcategory: '',
    summary: '',
    relevance_score: 0,
    relevance_reason: 'AI parse failed'
  };
  try { return { ...fallback, ...JSON.parse(stripFence(raw)) }; }
  catch (_e) { return fallback; }
}

function isAllPlaceholder(value) {
  const text = String(value || '').trim().toLowerCase();
  if (!text) return false;
  return [
    'all',
    'all category',
    'all categories',
    'all subcategory',
    'all sub-category',
    'all subcategories',
    'all sub-categories',
    'all sub categories'
  ].includes(text);
}

function aiSubcategory(ai) {
  return String(
    ai?.subcategory ||
    ai?.sub_category ||
    ai?.subCategory ||
    ai?.['sub-category'] ||
    ai?.['sub category'] ||
    ''
  ).trim();
}

function bestSubcategory(articleSubcategory, ai) {
  const existing = String(articleSubcategory || '').trim();
  const fromAi = aiSubcategory(ai);
  return isAllPlaceholder(existing) ? fromAi : (existing || fromAi);
}

